import { HealthService } from '../../../services/health.service.js';
import { navigate } from '../../../router.js';
import { buildSectionPage } from '../../../utils/section-page.utils.js';
import { createScreenStatusNodes, createScreenStatusMixin } from '../../_shared/screen-status.js';
import { createComponentLogger } from '../../../utils/component-logger.js';
import { safeExec } from '../../../utils/safe-exec.js';
import {
    HEALTH_EVENTS,
    type ExerciseRemoveFromSessionEvent,
    type StrengthSetAddRequestEvent,
    type StrengthSetCompleteEvent,
    type StrengthSetDeleteEvent,
    type StrengthSetEditEvent,
} from '../health-events.js';
import '../exercise-session-card/exercise-session-card.component.js';
import type { ExerciseSessionCard } from '../exercise-session-card/exercise-session-card.component.js';
import '../exercise-create-form/exercise-create-form.component.js';
import type { ExerciseCreateForm } from '../exercise-create-form/exercise-create-form.component.js';
import '../workout-blocks-editor/workout-blocks-editor.component.js';
import type { WorkoutBlocksEditor, WorkoutBlockInput } from '../workout-blocks-editor/workout-blocks-editor.component.js';
import type { Exercise, NewExercise, StrengthSet, WorkoutSessionWithDetail } from '@motivation/shared';
import type { ScreenComponent } from '../../../types/screen-component.js';
import { documentStyleSheet } from '../../../utils/css.js';
import stylesText from './strength-logging-screen.css?inline';

documentStyleSheet(stylesText);

/**
 * Strength-logging screen at `/health/workouts/:activityId`. Light-DOM
 * (matches other top-level health screens). Loads the session, owns the
 * exercise-add picker, and routes typed STRENGTH_SET_* / EXERCISE_* events
 * through to the API. Refetches on mount per the ScreenComponent contract.
 */
export class StrengthLoggingScreen extends HTMLElement implements ScreenComponent {
    private initialized = false;
    private activityIdValue: string | null = null;
    private contentRoot: HTMLElement | null = null;
    private cardsRoot: HTMLElement | null = null;
    private notesInput: HTMLTextAreaElement | null = null;
    private pickerRoot: HTMLElement | null = null;
    private blocksEditor: WorkoutBlocksEditor | null = null;
    private exerciseLibrary: Exercise[] = [];
    private session: WorkoutSessionWithDetail | null = null;

    private readonly log = createComponentLogger('strength-logging-screen');
    private statusNodes = createScreenStatusNodes();
    private statusMixin = createScreenStatusMixin(this.statusNodes.loadingNode, this.statusNodes.errorNode, this.statusNodes.retryNode);

    setLoading(): void { this.statusMixin.setLoading(); }
    setError(err: unknown): void { this.statusMixin.setError(err); }
    clearStatus(): void { this.statusMixin.clearStatus(); }

    set activityId(value: string | null) {
        this.activityIdValue = value;
    }

    connectedCallback(): void {
        if (this.initialized) return;
        this.initialized = true;

        const page = buildSectionPage(this, 'Workout', 'health', '/health');
        this.contentRoot = page.content;

        const meta = document.createElement('div');
        meta.className = 'strength-screen__meta';
        const titleNode = document.createElement('h2');
        titleNode.className = 'strength-screen__title';
        titleNode.textContent = 'Strength session';
        meta.appendChild(titleNode);

        this.notesInput = document.createElement('textarea');
        this.notesInput.className = 'strength-screen__notes';
        this.notesInput.placeholder = 'Session notes…';
        this.notesInput.addEventListener('change', () => this.handleNotesChange());
        meta.appendChild(this.notesInput);

        this.cardsRoot = document.createElement('div');
        this.cardsRoot.className = 'strength-screen__cards';

        this.pickerRoot = document.createElement('div');
        this.pickerRoot.className = 'strength-screen__picker';

        // Interval / round blocks (story 180) — co-located here since they share
        // the workout_session with the strength sets. Used for HIT sessions like
        // TRIB3 (e.g. "Round 1: bike, run, weights").
        const blocksSection = document.createElement('div');
        blocksSection.className = 'strength-screen__blocks';
        const blocksHeading = document.createElement('h3');
        blocksHeading.className = 'strength-screen__section-title';
        blocksHeading.textContent = 'Rounds & intervals';
        this.blocksEditor = document.createElement('workout-blocks-editor') as WorkoutBlocksEditor;
        this.blocksEditor.onAdd = (payload) => { void this.handleAddBlock(payload); };
        this.blocksEditor.onUpdate = (id, payload) => { void this.handleUpdateBlock(id, payload); };
        this.blocksEditor.onDelete = (id) => { void this.handleDeleteBlock(id); };
        this.blocksEditor.onReorder = (id, direction) => { void this.handleReorderBlock(id, direction); };
        blocksSection.append(blocksHeading, this.blocksEditor);

        this.statusNodes.loadingNode.textContent = 'Loading workout…';
        this.statusNodes.retryNode.addEventListener('click', () => { void this.loadSession(); });

        this.contentRoot.append(
            this.statusNodes.loadingNode,
            this.statusNodes.errorNode,
            this.statusNodes.retryNode,
            meta,
            this.cardsRoot,
            this.pickerRoot,
            blocksSection,
        );

        this.wireSessionEventHandlers();
        void this.loadSession();
    }

    private async loadSession(): Promise<void> {
        if (!this.activityIdValue || !this.contentRoot) return;
        return safeExec(this, this.log, async () => {
            const [session, library] = await Promise.all([
                HealthService.fetchWorkoutSession(this.activityIdValue!),
                HealthService.listExercises(),
            ]);
            if (!session) throw new Error(`Workout session ${this.activityIdValue} not found.`);
            this.session = session;
            this.exerciseLibrary = library;
            if (this.notesInput) this.notesInput.value = session.notes ?? '';
            await this.renderCards();
            this.renderPicker();
            if (this.blocksEditor) this.blocksEditor.blocks = session.workout_blocks;
        });
    }

    private async handleAddBlock(payload: WorkoutBlockInput): Promise<void> {
        if (!this.activityIdValue) return;
        return safeExec(this, this.log, async () => {
            await HealthService.appendWorkoutBlock(this.activityIdValue!, payload);
            await this.loadSession();
        });
    }

    private async handleUpdateBlock(id: string, payload: WorkoutBlockInput): Promise<void> {
        return safeExec(this, this.log, async () => {
            await HealthService.updateWorkoutBlock(id, payload);
            await this.loadSession();
        });
    }

    private async handleDeleteBlock(id: string): Promise<void> {
        return safeExec(this, this.log, async () => {
            await HealthService.deleteWorkoutBlock(id);
            await this.loadSession();
        });
    }

    private async handleReorderBlock(id: string, direction: 'up' | 'down'): Promise<void> {
        if (!this.session) return;
        const sorted = [...this.session.workout_blocks].sort((a, b) => a.position - b.position);
        const i = sorted.findIndex((b) => b.id === id);
        const j = direction === 'up' ? i - 1 : i + 1;
        if (i < 0 || j < 0 || j >= sorted.length) return;
        const a = sorted[i];
        const b = sorted[j];
        return safeExec(this, this.log, async () => {
            // Swap the two blocks' positions so the global order shifts by one.
            await HealthService.updateWorkoutBlock(a.id, { position: b.position });
            await HealthService.updateWorkoutBlock(b.id, { position: a.position });
            await this.loadSession();
        });
    }

    private async renderCards(): Promise<void> {
        if (!this.cardsRoot || !this.session) return;

        // Group sets by exercise_id, preserve first-seen order.
        const byExercise = new Map<string, StrengthSet[]>();
        for (const set of this.session.strength_sets) {
            const list = byExercise.get(set.exercise_id) ?? [];
            list.push(set);
            byExercise.set(set.exercise_id, list);
        }

        // Fetch the previous-session shadow column data in parallel — one
        // request per distinct exercise in this session.
        const previousByExercise = new Map<string, StrengthSet[]>();
        await Promise.all(
            [...byExercise.keys()].map(async (exerciseId) => {
                try {
                    const previous = await HealthService.fetchRecentStrengthSetsForExercise(exerciseId, 5);
                    // Exclude rows from the current session so "prev" is genuinely previous.
                    const filtered = previous.filter((s) => s.session_id !== this.activityIdValue);
                    previousByExercise.set(exerciseId, filtered);
                } catch (err) {
                    this.log.warn('Failed to load previous strength sets', { exerciseId, err });
                }
            }),
        );

        const cards = [...byExercise.entries()].flatMap(([exerciseId, sets]) => {
            const exercise = this.exerciseLibrary.find((e) => e.id === exerciseId);
            if (!exercise) return [];
            const card = document.createElement('exercise-session-card') as ExerciseSessionCard;
            card.exercise = exercise;
            card.sets = sets;
            card.previousSets = previousByExercise.get(exerciseId) ?? [];
            return [card];
        });
        this.cardsRoot.replaceChildren(...cards);
    }

    private renderPicker(): void {
        if (!this.pickerRoot) return;
        this.pickerRoot.replaceChildren();

        const toggleBtn = document.createElement('button');
        toggleBtn.className = 'strength-screen__picker-toggle';
        toggleBtn.type = 'button';
        toggleBtn.textContent = '+ Add exercise';
        this.pickerRoot.appendChild(toggleBtn);

        const panel = document.createElement('div');
        panel.className = 'strength-screen__picker-panel';
        panel.hidden = true;
        this.pickerRoot.appendChild(panel);

        const manageLink = document.createElement('button');
        manageLink.type = 'button';
        manageLink.className = 'strength-screen__manage-link';
        manageLink.textContent = 'Manage exercises';
        manageLink.addEventListener('click', () => navigate('/health/exercises'));
        this.pickerRoot.appendChild(manageLink);

        const templatesLink = document.createElement('button');
        templatesLink.type = 'button';
        templatesLink.className = 'strength-screen__manage-link';
        templatesLink.textContent = 'Workout templates';
        templatesLink.addEventListener('click', () => navigate('/health/workout-templates'));
        this.pickerRoot.appendChild(templatesLink);

        const searchInput = document.createElement('input');
        searchInput.className = 'strength-screen__picker-search';
        searchInput.placeholder = 'Search exercises…';
        panel.appendChild(searchInput);

        const list = document.createElement('ul');
        list.className = 'strength-screen__picker-list';
        panel.appendChild(list);

        const renderList = () => {
            const raw = searchInput.value.trim();
            const q = raw.toLowerCase();
            const matches = q
                ? this.exerciseLibrary.filter((e) => e.display_name.toLowerCase().includes(q) || e.canonical_name.toLowerCase().includes(q))
                : this.exerciseLibrary;
            const items = matches.slice(0, 50).map((exercise) => {
                const item = document.createElement('li');
                item.className = 'strength-screen__picker-item';
                item.textContent = exercise.display_name;
                item.addEventListener('click', () => this.handleAddExercise(exercise));
                return item;
            });
            // Always offer inline create — labelled with the typed query when
            // present — so a missing movement never blocks logging (story 177).
            const createItem = document.createElement('li');
            createItem.className = 'strength-screen__picker-item strength-screen__picker-create';
            createItem.textContent = raw ? `+ Create “${raw}”` : '+ New exercise';
            createItem.addEventListener('click', () => this.showCreateForm(panel, searchInput, list, raw));
            items.push(createItem);
            list.replaceChildren(...items);
        };

        toggleBtn.addEventListener('click', () => {
            panel.hidden = !panel.hidden;
            if (!panel.hidden) {
                searchInput.value = '';
                searchInput.hidden = false;
                list.hidden = false;
                renderList();
                searchInput.focus();
            }
        });
        searchInput.addEventListener('input', renderList);
    }

    private showCreateForm(panel: HTMLElement, searchInput: HTMLElement, list: HTMLElement, presetName: string): void {
        searchInput.hidden = true;
        list.hidden = true;

        const form = document.createElement('exercise-create-form') as ExerciseCreateForm;
        form.presetName = presetName;
        form.onCancel = () => {
            form.remove();
            searchInput.hidden = false;
            list.hidden = false;
        };
        form.onSubmit = (payload) => { void this.handleCreateExercise(payload, form); };
        panel.appendChild(form);
    }

    private async handleCreateExercise(payload: NewExercise, form: ExerciseCreateForm): Promise<void> {
        if (!this.activityIdValue) return;
        // Not via safeExec: on failure we keep the form mounted and show the
        // error inline so the user doesn't lose what they typed.
        try {
            const created = await HealthService.createExercise(payload);
            this.exerciseLibrary.push(created);
            await this.handleAddExercise(created);
        } catch (err) {
            this.log.warn('Failed to create exercise', { err });
            form.showError('Could not create exercise. It may already exist.');
        }
    }

    private wireSessionEventHandlers(): void {
        // Cards/rows bubble typed events up here.
        this.addEventListener(HEALTH_EVENTS.STRENGTH_SET_EDIT, (e: StrengthSetEditEvent) => {
            void this.handleEditSet(e.detail.set_id, e.detail.updates);
        });
        this.addEventListener(HEALTH_EVENTS.STRENGTH_SET_COMPLETE, (e: StrengthSetCompleteEvent) => {
            void this.handleCompleteSet(e.detail.set_id);
        });
        this.addEventListener(HEALTH_EVENTS.STRENGTH_SET_DELETE, (e: StrengthSetDeleteEvent) => {
            void this.handleDeleteSet(e.detail.set_id);
        });
        this.addEventListener(HEALTH_EVENTS.STRENGTH_SET_ADD_REQUEST, (e: StrengthSetAddRequestEvent) => {
            void this.handleAddSet(e.detail.exercise_id);
        });
        this.addEventListener(HEALTH_EVENTS.EXERCISE_REMOVE_FROM_SESSION, (e: ExerciseRemoveFromSessionEvent) => {
            void this.handleRemoveExercise(e.detail.exercise_id);
        });
    }

    private async handleNotesChange(): Promise<void> {
        if (!this.activityIdValue || !this.notesInput || !this.session) return;
        return safeExec(this, this.log, async () => {
            const notes = this.notesInput!.value;
            await HealthService.updateWorkoutSession(this.activityIdValue!, { notes: notes || null });
            this.session!.notes = notes || undefined;
        });
    }

    private async handleEditSet(setId: string, updates: Partial<StrengthSet>): Promise<void> {
        return safeExec(this, this.log, async () => {
            const updated = await HealthService.updateStrengthSet(setId, updates);
            this.applySetUpdate(updated);
        });
    }

    private async handleCompleteSet(setId: string): Promise<void> {
        // The rest timer is started locally by the card. The screen marks the
        // row visually completed by toggling the attribute on the matching row.
        const row = this.findRowForSet(setId);
        if (row) row.setAttribute('completed', '');
    }

    private async handleDeleteSet(setId: string): Promise<void> {
        return safeExec(this, this.log, async () => {
            await HealthService.deleteStrengthSet(setId);
            await this.loadSession();
        });
    }

    private async handleAddSet(exerciseId: string): Promise<void> {
        if (!this.activityIdValue) return;
        return safeExec(this, this.log, async () => {
            await HealthService.appendStrengthSet(this.activityIdValue!, { exercise_id: exerciseId });
            await this.loadSession();
        });
    }

    private async handleAddExercise(exercise: Exercise): Promise<void> {
        if (!this.activityIdValue) return;
        return safeExec(this, this.log, async () => {
            // Adding an exercise means appending its first set (set_index=1, position=N).
            await HealthService.appendStrengthSet(this.activityIdValue!, { exercise_id: exercise.id });
            await this.loadSession();
        });
    }

    private async handleRemoveExercise(exerciseId: string): Promise<void> {
        if (!this.session) return;
        return safeExec(this, this.log, async () => {
            const setsToRemove = this.session!.strength_sets.filter((s) => s.exercise_id === exerciseId);
            for (const set of setsToRemove) {
                await HealthService.deleteStrengthSet(set.id);
            }
            await this.loadSession();
        });
    }

    private applySetUpdate(updated: StrengthSet): void {
        if (!this.session) return;
        const idx = this.session.strength_sets.findIndex((s) => s.id === updated.id);
        if (idx >= 0) this.session.strength_sets[idx] = updated;
    }

    private findRowForSet(setId: string): HTMLElement | null {
        if (!this.cardsRoot) return null;
        const cards = Array.from(this.cardsRoot.querySelectorAll('exercise-session-card')) as ExerciseSessionCard[];
        for (const card of cards) {
            const row = card.shadowRoot?.querySelector(`strength-set-row[data-set-id="${CSS.escape(setId)}"]`) as HTMLElement | null;
            if (row) return row;
        }
        return null;
    }
}

/**
 * Create a fresh manual workout activity + empty workout_session and navigate
 * to the new strength-logging screen. Used by the "New workout" CTA on the
 * day-detail screen so the screen itself stays single-purpose (load existing).
 */
export async function startFreshWorkoutSession(date: string, title = 'Workout'): Promise<void> {
    const activity = await HealthService.createActivity({
        title,
        type: 'weight_training',
        date,
        source: 'manual',
    });
    await HealthService.createWorkoutSession({ activity_id: activity.id });
    navigate(`/health/workouts/${encodeURIComponent(activity.id)}`, { history: 'push' });
}

if (!customElements.get('strength-logging-screen')) {
    customElements.define('strength-logging-screen', StrengthLoggingScreen);
}
