import stylesText from './workout-blocks-editor.css?inline';
import { cssStyleSheet } from '../../../utils/css.js';
import { WORKOUT_BLOCK_KINDS } from '@motivation/shared';
import type { WorkoutBlock, WorkoutBlockKind } from '@motivation/shared';

const styles = cssStyleSheet(stylesText);

/** The user-editable subset of a block (no id/session_id/position). */
export interface WorkoutBlockInput {
    parent_label?: string;
    kind: WorkoutBlockKind;
    modality?: string;
    duration_s?: number;
    intensity?: string;
    avg_hr?: number;
    notes?: string;
}

/**
 * Editor for a workout session's interval `workout_blocks` (story 180) — the
 * round/interval structure of HIT-style sessions like TRIB3 (e.g. "Round 1:
 * bike 5min, run 5min"). Co-located on the strength screen since blocks and
 * strength sets share one workout_session. Callback-driven; the screen owns
 * persistence + reload. Future stories 147/148 auto-populate blocks into this UI.
 */
export class WorkoutBlocksEditor extends HTMLElement {
    private _blocks: WorkoutBlock[] = [];
    private editing: WorkoutBlock | 'new' | null = null;

    private _onAdd: ((payload: WorkoutBlockInput) => void) | null = null;
    private _onUpdate: ((id: string, payload: WorkoutBlockInput) => void) | null = null;
    private _onDelete: ((id: string) => void) | null = null;
    private _onReorder: ((id: string, direction: 'up' | 'down') => void) | null = null;

    private root: HTMLElement;

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        this.root = document.createElement('div');
        shadow.appendChild(this.root);
    }

    set blocks(value: WorkoutBlock[]) {
        this._blocks = [...value].sort((a, b) => a.position - b.position);
        this.render();
    }

    set onAdd(handler: (payload: WorkoutBlockInput) => void) { this._onAdd = handler; }
    set onUpdate(handler: (id: string, payload: WorkoutBlockInput) => void) { this._onUpdate = handler; }
    set onDelete(handler: (id: string) => void) { this._onDelete = handler; }
    set onReorder(handler: (id: string, direction: 'up' | 'down') => void) { this._onReorder = handler; }

    private render(): void {
        this.root.replaceChildren(this.editing ? this.renderForm() : this.renderList());
    }

    private renderList(): DocumentFragment {
        const frag = document.createDocumentFragment();

        if (this._blocks.length === 0) {
            const empty = document.createElement('p');
            empty.className = 'wbe__empty';
            empty.textContent = 'No intervals yet.';
            frag.appendChild(empty);
        } else {
            // Group by parent_label, preserving first-seen (position) order.
            const groups: { label: string; blocks: WorkoutBlock[] }[] = [];
            for (const block of this._blocks) {
                const label = block.parent_label?.trim() || 'Intervals';
                let group = groups.find((g) => g.label === label);
                if (!group) { group = { label, blocks: [] }; groups.push(group); }
                group.blocks.push(block);
            }

            for (const group of groups) {
                const groupEl = document.createElement('div');
                groupEl.className = 'wbe__group';
                const heading = document.createElement('h4');
                heading.className = 'wbe__group-title';
                heading.textContent = group.label;
                groupEl.appendChild(heading);
                for (const block of group.blocks) groupEl.appendChild(this.renderRow(block));
                frag.appendChild(groupEl);
            }
        }

        const addBtn = document.createElement('button');
        addBtn.type = 'button';
        addBtn.className = 'wbe__btn wbe__add';
        addBtn.textContent = '+ Add interval';
        addBtn.addEventListener('click', () => { this.editing = 'new'; this.render(); });
        frag.appendChild(addBtn);
        return frag;
    }

    private renderRow(block: WorkoutBlock): HTMLElement {
        const row = document.createElement('div');
        row.className = 'wbe__row';

        const desc = document.createElement('span');
        desc.className = 'wbe__desc';
        desc.textContent = describeBlock(block);
        row.appendChild(desc);

        const actions = document.createElement('div');
        actions.className = 'wbe__row-actions';
        actions.append(
            this.iconButton('↑', 'Move up', () => this._onReorder?.(block.id, 'up')),
            this.iconButton('↓', 'Move down', () => this._onReorder?.(block.id, 'down')),
            this.iconButton('Edit', 'Edit', () => { this.editing = block; this.render(); }),
            this.iconButton('✕', 'Delete', () => { if (confirm('Delete this interval?')) this._onDelete?.(block.id); }),
        );
        row.appendChild(actions);
        return row;
    }

    private iconButton(label: string, title: string, onClick: () => void): HTMLButtonElement {
        const btn = document.createElement('button');
        btn.type = 'button';
        btn.className = 'wbe__btn wbe__icon';
        btn.textContent = label;
        btn.title = title;
        btn.addEventListener('click', onClick);
        return btn;
    }

    private renderForm(): HTMLElement {
        const existing = this.editing === 'new' ? null : this.editing;
        const form = document.createElement('form');
        form.className = 'wbe__form';

        const label = textField('Round / group', existing?.parent_label ?? '', 'e.g. Round 1');
        const kind = selectField('Kind', WORKOUT_BLOCK_KINDS as readonly string[], existing?.kind ?? 'interval');
        const modality = textField('Modality', existing?.modality ?? '', 'e.g. bike / run / weights');
        const duration = numberField('Duration (sec)', existing?.duration_s);
        const intensity = textField('Intensity', existing?.intensity ?? '', 'e.g. zone 4 / RPE 8');
        const avgHr = numberField('Avg HR (bpm)', existing?.avg_hr);
        const notes = textField('Notes', existing?.notes ?? '', 'optional');

        const grid = document.createElement('div');
        grid.className = 'wbe__form-grid';
        grid.append(label.field, kind.field, modality.field, duration.field, intensity.field, avgHr.field);

        const actions = document.createElement('div');
        actions.className = 'wbe__form-actions';
        const cancel = document.createElement('button');
        cancel.type = 'button';
        cancel.className = 'wbe__btn';
        cancel.textContent = 'Cancel';
        cancel.addEventListener('click', () => { this.editing = null; this.render(); });
        const submit = document.createElement('button');
        submit.type = 'submit';
        submit.className = 'wbe__btn wbe__btn--primary';
        submit.textContent = existing ? 'Save' : 'Add';
        actions.append(cancel, submit);

        form.append(grid, notes.field, actions);
        form.addEventListener('submit', (e) => {
            e.preventDefault();
            const payload: WorkoutBlockInput = {
                parent_label: label.value() || undefined,
                kind: kind.value() as WorkoutBlockKind,
                modality: modality.value() || undefined,
                duration_s: duration.value(),
                intensity: intensity.value() || undefined,
                avg_hr: avgHr.value(),
                notes: notes.value() || undefined,
            };
            if (existing) this._onUpdate?.(existing.id, payload);
            else this._onAdd?.(payload);
            this.editing = null;
        });
        return form;
    }
}

function describeBlock(block: WorkoutBlock): string {
    const parts: string[] = [];
    if (block.modality) parts.push(block.modality);
    if (block.duration_s != null) parts.push(formatDuration(block.duration_s));
    if (block.intensity) parts.push(block.intensity);
    if (block.avg_hr != null) parts.push(`${block.avg_hr} bpm`);
    const base = parts.join(' · ') || block.kind;
    return block.kind === 'rest' && !block.modality ? `Rest · ${base}` : base;
}

function formatDuration(sec: number): string {
    if (sec < 60) return `${sec}s`;
    const m = Math.floor(sec / 60);
    const s = sec % 60;
    return s === 0 ? `${m}min` : `${m}:${String(s).padStart(2, '0')}`;
}

function textField(labelText: string, value: string, placeholder = ''): { field: HTMLElement; value: () => string } {
    const wrap = document.createElement('label');
    wrap.className = 'wbe__field';
    const span = document.createElement('span');
    span.textContent = labelText;
    const input = document.createElement('input');
    input.type = 'text';
    input.className = 'wbe__input';
    input.value = value;
    input.placeholder = placeholder;
    wrap.append(span, input);
    return { field: wrap, value: () => input.value.trim() };
}

function numberField(labelText: string, value: number | undefined): { field: HTMLElement; value: () => number | undefined } {
    const wrap = document.createElement('label');
    wrap.className = 'wbe__field';
    const span = document.createElement('span');
    span.textContent = labelText;
    const input = document.createElement('input');
    input.type = 'number';
    input.min = '0';
    input.className = 'wbe__input';
    input.placeholder = 'optional';
    if (value != null) input.value = String(value);
    wrap.append(span, input);
    return {
        field: wrap,
        value: () => {
            const raw = input.value.trim();
            if (!raw) return undefined;
            const n = Number(raw);
            return Number.isFinite(n) && n >= 0 ? n : undefined;
        },
    };
}

function selectField(labelText: string, options: readonly string[], value: string): { field: HTMLElement; value: () => string } {
    const wrap = document.createElement('label');
    wrap.className = 'wbe__field';
    const span = document.createElement('span');
    span.textContent = labelText;
    const select = document.createElement('select');
    select.className = 'wbe__input';
    for (const opt of options) {
        const o = document.createElement('option');
        o.value = opt;
        o.textContent = opt.charAt(0).toUpperCase() + opt.slice(1);
        select.appendChild(o);
    }
    select.value = value;
    wrap.append(span, select);
    return { field: wrap, value: () => select.value };
}

if (!customElements.get('workout-blocks-editor')) {
    customElements.define('workout-blocks-editor', WorkoutBlocksEditor);
}
