import stylesText from './strength-set-row.css?inline';
import { cssStyleSheet } from '../../../utils/css.js';
import type { StrengthSet, NewStrengthSet } from '@motivation/shared';
import {
    createStrengthSetCompleteEvent,
    createStrengthSetDeleteEvent,
    createStrengthSetEditEvent,
} from '../health-events.js';

const styles = cssStyleSheet(stylesText);

const template = document.createElement('template');
template.innerHTML = `
    <div class="row" part="row">
        <span class="set-index" part="set-index"></span>
        <span class="previous" part="previous"></span>
        <input class="input" data-field="reps" type="number" inputmode="numeric" min="0" placeholder="reps" aria-label="reps">
        <input class="input wide" data-field="weight_kg" type="number" inputmode="decimal" min="0" step="0.5" placeholder="kg" aria-label="weight in kilograms">
        <input class="input" data-field="rpe" type="number" inputmode="decimal" min="0" max="10" step="0.5" placeholder="RPE" aria-label="RPE">
        <button class="action-btn complete" type="button" aria-pressed="false" aria-label="Mark set complete">✓</button>
        <button class="action-btn delete" type="button" aria-label="Delete set">✕</button>
    </div>
`;

/**
 * One row of an exercise card. Owns nothing — receives a `StrengthSet` and an
 * optional `previousSet` via properties, emits typed `STRENGTH_SET_*` events
 * to the screen, which does the API work and re-renders on success.
 */
export class StrengthSetRow extends HTMLElement {
    static get observedAttributes() { return ['completed']; }

    private setValue: StrengthSet | null = null;
    private previousValue: StrengthSet | null = null;
    private row!: HTMLElement;
    private setIndexNode!: HTMLElement;
    private previousNode!: HTMLElement;
    private repsInput!: HTMLInputElement;
    private weightInput!: HTMLInputElement;
    private rpeInput!: HTMLInputElement;
    private completeBtn!: HTMLButtonElement;
    private deleteBtn!: HTMLButtonElement;

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));
        this.row = shadow.querySelector('.row') as HTMLElement;
        this.setIndexNode = shadow.querySelector('.set-index') as HTMLElement;
        this.previousNode = shadow.querySelector('.previous') as HTMLElement;
        this.repsInput = shadow.querySelector('[data-field="reps"]') as HTMLInputElement;
        this.weightInput = shadow.querySelector('[data-field="weight_kg"]') as HTMLInputElement;
        this.rpeInput = shadow.querySelector('[data-field="rpe"]') as HTMLInputElement;
        this.completeBtn = shadow.querySelector('.action-btn.complete') as HTMLButtonElement;
        this.deleteBtn = shadow.querySelector('.action-btn.delete') as HTMLButtonElement;

        // Listeners on own shadow DOM — attach once in the constructor so a
        // disconnect/reconnect cycle doesn't double-bind. Lifetime tracks the
        // shadow tree, so no explicit cleanup is needed.
        this.repsInput.addEventListener('change', () => this.emitEditOnChange('reps', this.repsInput.value));
        this.weightInput.addEventListener('change', () => this.emitEditOnChange('weight_kg', this.weightInput.value));
        this.rpeInput.addEventListener('change', () => this.emitEditOnChange('rpe', this.rpeInput.value));
        this.completeBtn.addEventListener('click', () => this.emitComplete());
        this.deleteBtn.addEventListener('click', () => this.emitDelete());
    }

    set set(value: StrengthSet) {
        this.setValue = value;
        this.setAttribute('data-set-id', value.id);
        this.render();
    }

    get set(): StrengthSet | null {
        return this.setValue;
    }

    set previousSet(value: StrengthSet | null) {
        this.previousValue = value;
        this.renderPrevious();
    }

    attributeChangedCallback(name: string): void {
        if (name === 'completed') this.renderCompletedState();
    }

    connectedCallback(): void {
        this.render();
    }

    private render(): void {
        if (!this.setValue) return;
        this.setIndexNode.textContent = `#${this.setValue.set_index}`;
        this.repsInput.value = String(this.setValue.reps ?? '');
        this.weightInput.value = String(this.setValue.weight_kg ?? '');
        this.rpeInput.value = String(this.setValue.rpe ?? '');
        this.renderPrevious();
        this.renderCompletedState();
    }

    private renderPrevious(): void {
        if (!this.previousValue) {
            this.previousNode.textContent = '';
            return;
        }
        const reps = this.previousValue.reps ?? '–';
        const w = this.previousValue.weight_kg != null ? `${this.previousValue.weight_kg}kg` : '';
        this.previousNode.textContent = `prev: ${reps}${w ? ` × ${w}` : ''}`;
    }

    private renderCompletedState(): void {
        const isCompleted = this.hasAttribute('completed');
        this.row.classList.toggle('completed', isCompleted);
        this.completeBtn.setAttribute('aria-pressed', isCompleted ? 'true' : 'false');
    }

    private emitEditOnChange(field: keyof NewStrengthSet, raw: string): void {
        if (!this.setValue) return;
        const updates: Partial<NewStrengthSet> = {};
        if (raw === '') {
            (updates as Record<string, unknown>)[field] = null;
        } else {
            const parsed = Number(raw);
            if (!Number.isFinite(parsed) || parsed < 0) return;
            (updates as Record<string, unknown>)[field] = parsed;
        }
        this.dispatchEvent(createStrengthSetEditEvent({ set_id: this.setValue.id, updates }));
    }

    private emitComplete(): void {
        if (!this.setValue) return;
        this.dispatchEvent(createStrengthSetCompleteEvent({
            set_id: this.setValue.id,
            exercise_id: this.setValue.exercise_id,
            rest_s: this.setValue.rest_s ?? null,
        }));
    }

    private emitDelete(): void {
        if (!this.setValue) return;
        this.dispatchEvent(createStrengthSetDeleteEvent({ set_id: this.setValue.id }));
    }
}

if (!customElements.get('strength-set-row')) {
    customElements.define('strength-set-row', StrengthSetRow);
}
